import stylesText from './goal-cube.css?inline';
import { cssStyleSheet } from '../../../../../utils/css.js';

const styles = cssStyleSheet(stylesText);

const template = document.createElement('template');
template.innerHTML = `
    <div class="cube" id="cube"></div>
`;

export class GoalCube extends HTMLElement {
    static get observedAttributes() {
        return ['status', 'title'];
    }

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    connectedCallback() {
        this.update();
    }

    attributeChangedCallback(_name: string, oldValue: string | null, newValue: string | null) {
        if (oldValue === newValue) return;
        this.update();
    }

    private update() {
        const cube = this.shadowRoot!.getElementById('cube')!;
        cube.className = `cube status-${(this.getAttribute('status') ?? 'ACTIVE').toLowerCase()}`;
        this.title = this.getAttribute('title') ?? '';
    }
}

if (!customElements.get('goal-cube')) {
    customElements.define('goal-cube', GoalCube);
}
