import stylesText from './goal-header-card.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';

const styles = cssStyleSheet(stylesText);
import type { Goal } from '@motivation/shared';
import {
    createGoalNavBackEvent,
    createGoalEditEvent,
    createGoalDeleteEvent,
} from '../goal-events.js';

const template = document.createElement('template');
template.innerHTML = `
    <div class="header-card" id="card">
        <button id="back-btn" class="back-btn" title="Back">←</button>
        <div class="title-section">
            <h2 class="title" id="title"></h2>
            <p class="description" id="description"></p>
        </div>
        <div class="actions">
            <button id="edit-btn" class="icon-btn" title="Edit">✎</button>
            <button id="delete-btn" class="icon-btn" title="Delete">🗑</button>
        </div>
    </div>
`;

export class GoalHeaderCard extends HTMLElement {
    private _goal?: Goal;

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    connectedCallback() {
        this.setupEvents();
        if (this._goal) this.update();
    }

    set goal(val: Goal | undefined) {
        this._goal = val;
        if (this.isConnected) {
            this.update();
        }
    }

    get goal(): Goal | undefined {
        return this._goal;
    }

    private setupEvents() {
        this.shadowRoot!.addEventListener('click', (e) => {
            const target = e.target as HTMLElement;
            if (target.closest('#back-btn')) {
                this.dispatchEvent(createGoalNavBackEvent());
            } else if (target.closest('#edit-btn') && this._goal) {
                this.dispatchEvent(createGoalEditEvent({ id: this._goal.id }));
            } else if (target.closest('#delete-btn') && this._goal) {
                this.dispatchEvent(createGoalDeleteEvent({ id: this._goal.id }));
            }
        });
    }

    private update() {
        const shadow = this.shadowRoot!;
        const card = shadow.getElementById('card') as HTMLElement;
        if (!card) return;

        if (!this._goal) {
            card.hidden = true;
            return;
        }

        card.hidden = false;
        shadow.getElementById('title')!.textContent = this._goal.title ?? '';
        shadow.getElementById('title')!.style.viewTransitionName = `title-${this._goal.id}`;
        shadow.getElementById('description')!.textContent = this._goal.description ?? '';
    }
}

if (!customElements.get('goal-header-card')) {
    customElements.define('goal-header-card', GoalHeaderCard);
}
