import type { Goal, NewGoal } from '@motivation/shared';
import { API_URL } from '../config.js';
import { apiError } from './http.js';

export class GoalService {
    static async fetchGoals(): Promise<Goal[]> {
        const response = await fetch(`${API_URL}/api/goals`);
        if (!response.ok) {
            throw await apiError(response, 'Failed to fetch goals');
        }
        return response.json();
    }

    static async createGoal(goal: NewGoal): Promise<Goal> {
        const response = await fetch(`${API_URL}/api/goals`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(goal)
        });
        if (!response.ok) {
            throw await apiError(response, 'Failed to create goal');
        }
        return response.json();
    }

    static async updateGoal(id: string, updates: Partial<Goal>): Promise<Goal> {
        const response = await fetch(`${API_URL}/api/goals/${id}`, {
            method: 'PATCH',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(updates)
        });
        if (!response.ok) {
            throw await apiError(response, 'Failed to update goal');
        }
        return response.json();
    }

    static async deleteGoal(id: string): Promise<void> {
        const response = await fetch(`${API_URL}/api/goals/${id}`, {
            method: 'DELETE'
        });
        if (!response.ok) {
            throw await apiError(response, 'Failed to delete goal');
        }
    }
}
